CustomShopBlock.curBlock = nil

function CustomShopBlock:onTabChange(isSelect)
    if isSelect then
        return
    end
    if CustomShopBlock.curBlock then
        GUICustomShop:unloadBodyPart(CustomShopBlock.curBlock.PartName)
        GUICustomShop:playSkill("idle")
        CustomShopBlock.curBlock = nil
    end
end

function CustomShopBlock:onSelectGoods(goods)
    local block = self.Settings[goods.SettingId]
    if not block then
        return
    end
    CustomShopBlock.curBlock = block
    GUICustomShop:useBodyPart(block.PartName, block.MeshName)
    GUICustomShop:playSkill(block.Action)
end